          hotel: { zh: "查看酒店", en: "View Hotel", pt: "Ver Hotel", es: "Ver Hotel", fr: "Voir l'hôtel", de: "Hotel ansehen", it: "Vedi Hotel", ja: "ホテルを見る", ko: "호텔 보기", ar: "عرض الفندق", ru: "Смотреть отель", vi: "Xem khách sạn" },
          landmark: { zh: "查看景点", en: "View Landmark", pt: "Ver Ponto Turístico", es: "Ver Monumento", fr: "Voir le site", de: "Sehenswürdigkeit", it: "Vedi Attrazione", ja: "観光地を見る", ko: "명소 보기", ar: "عرض المعلم", ru: "Смотреть", vi: "Xem điểm đến" },
